function bulkTransfer(
    TransferHelperItemsWithRecipient[] calldata items,
    bytes32 conduitKey
) external override returns (bytes4 magicValue) {
    // Ensure that a conduit key has been supplied.
    if (conduitKey == bytes32(0)) {
        revert InvalidConduit(conduitKey, address(0));
    }

    // Use conduit derived from supplied conduit key to perform transfers.
    _performTransfersWithConduit(items, conduitKey);

    // Return a magic value indicating that the transfers were performed.
    magicValue = this.bulkTransfer.selector;
}

function canCall(
    address user,
    address target,
    bytes4 functionSig
) public view virtual override returns (bool) {
    Authority customAuthority = getTargetCustomAuthority[target];

    if (address(customAuthority) != address(0)) return customAuthority.canCall(user, target, functionSig);

    return
        isCapabilityPublic[functionSig] || bytes32(0) != getUserRoles[user] & getRolesWithCapability[functionSig];
}

function _approve(address owner, address spender, uint256 amount) internal virtual {
    require(owner != address(0), "ERC20: approve from the zero address");
    require(spender != address(0), "ERC20: approve to the zero address");

    _allowances[owner][spender] = amount;
    emit Approval(owner, spender, amount);
}

function ln(UD60x18 x) pure returns (UD60x18 result) {
    unchecked {
        // Inline the fixed-point multiplication to save gas. This is overflow-safe because the maximum value that
        // {log2} can return is ~196_205294292027477728.
        result = wrap(log2(x).unwrap() * uUNIT / uLOG2_E);
    }
}

function prepare(
    NavigatorRequest calldata request
) public view returns (NavigatorResponse memory) {
    NavigatorContext memory context = NavigatorContextLib
        .from(request)
        .withEmptyResponse();

    for (uint256 i; i < helpers.length; i++) {
        context = helpers[i].prepare(context);
    }

    return context.response;
}

function hashWithWitness(
    ISignatureTransfer.PermitTransferFrom memory permit,
    bytes32 witness,
    string calldata witnessTypeString
) internal view returns (bytes32) {
    bytes32 typeHash = keccak256(abi.encodePacked(_PERMIT_TRANSFER_FROM_WITNESS_TYPEHASH_STUB, witnessTypeString));

    bytes32 tokenPermissionsHash = _hashTokenPermissions(permit.permitted);
    return keccak256(abi.encode(typeHash, tokenPermissionsHash, msg.sender, permit.nonce, permit.deadline, witness));
}

function getNextSqrtPriceFromOutput(
    uint160 sqrtPX96,
    uint128 liquidity,
    uint256 amountOut,
    bool zeroForOne
) internal pure returns (uint160 sqrtQX96) {
    require(sqrtPX96 > 0);
    require(liquidity > 0);

    // round to make sure that we pass the target price
    return
        zeroForOne
            ? getNextSqrtPriceFromAmount1RoundingDown(sqrtPX96, liquidity, amountOut, false)
            : getNextSqrtPriceFromAmount0RoundingUp(sqrtPX96, liquidity, amountOut, false);
}

function compatAllowance(
    IERC20Token token,
    address owner,
    address spender
) internal view returns (uint256 allowance_) {
    (bool didSucceed, bytes memory resultData) = address(token).staticcall(
        abi.encodeWithSelector(token.allowance.selector, owner, spender)
    );
    if (didSucceed && resultData.length >= 32) {
        allowance_ = LibBytesV06.readUint256(resultData, 0);
    }
}

